14: // GraphBuilder is an interface that can be implemented and used with
15: // Terraform to build the graph that Terraform walks.
16: type GraphBuilder interface {
17: 	// Build builds the graph for the given module path. It is up to
18: 	// the interface implementation whether this build should expand
19: 	// the graph or not.
20: 	Build(addrs.ModuleInstance) (*Graph, tfdiags.Diagnostics)
21: }
22: 
23: // BasicGraphBuilder is a GraphBuilder that builds a graph out of a
24: // series of transforms and (optionally) validates the graph is a valid
25: // structure.
26: type BasicGraphBuilder struct {
27: 	Steps []GraphTransformer
28: 	// Optional name to add to the graph debug log
29: 	Name string
30: 
31: 	// SkipGraphValidation indicates whether the graph validation (enabled by default)
32: 	// should be skipped after the graph is built.
33: 	SkipGraphValidation bool
34: }
35: 
36: func (b *BasicGraphBuilder) Build(path addrs.ModuleInstance) (*Graph, tfdiags.Diagnostics) {
37: 	var diags tfdiags.Diagnostics
38: 	g := &Graph{Path: path}
39: 
40: 	var lastStepStr string
41: 	for _, step := range b.Steps {
42: 		if step == nil {
43: 			continue
44: 		}
45: 		log.Printf("[TRACE] Executing graph transform %T", step)
46: 
47: 		err := step.Transform(g)
48: 
49: 		if logging.GraphTrace {
50: 			if thisStepStr := g.StringWithNodeTypes(); thisStepStr != lastStepStr {
51: 				log.Printf("[TRACE] Completed graph transform %T with new graph:\n%s  ------", step, logging.Indent(thisStepStr))
52: 				lastStepStr = thisStepStr
53: 			} else {
54: 				log.Printf("[TRACE] Completed graph transform %T (no changes)", step)
55: 			}
56: 		}
57: 
58: 		if err != nil {
59: 			if nf, isNF := err.(tfdiags.NonFatalError); isNF {
60: 				diags = diags.Append(nf.Diagnostics)
61: 			} else if diag, isDiag := err.(tfdiags.DiagnosticsAsError); isDiag {
62: 				diags = diags.Append(diag.Diagnostics)
63: 				return g, diags
64: 			} else {
65: 				diags = diags.Append(err)
66: 				return g, diags
67: 			}
68: 		}
69: 	}
70: 
71: 	if !logging.GraphTrace {
72: 		// print the graph at least once for normal trace logs
73: 		log.Printf("[TRACE] Completed graph transform:\n%s  ------", g.StringWithNodeTypes())
74: 	}
75: 
76: 	// Return early if the graph validation is skipped
77: 	// This behavior is currently only used by the graph command
78: 	// which only wants to display the dot representation of the graph
79: 	if b.SkipGraphValidation {
80: 		return g, diags
81: 	}
82: 
83: 	if err := g.Validate(); err != nil {
84: 		log.Printf("[ERROR] Graph validation failed. Graph:\n\n%s", g.String())
85: 		diags = diags.Append(err)
86: 		return nil, diags
87: 	}
88: 
89: 	return g, diags
90: }
